-- helper function (idempotent)
CREATE OR REPLACE FUNCTION public.set_updated_at()
RETURNS TRIGGER AS $$ BEGIN NEW.updated_at = now(); RETURN NEW; END; $$
LANGUAGE plpgsql SET search_path = public;

-- ============================================================
-- onboarding_content
-- ============================================================
CREATE TABLE IF NOT EXISTS public.onboarding_content (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  section text NOT NULL CHECK (section IN ('profile','companies','vacancies','interviews','training','crm','billing')),
  field_key text,
  kind text NOT NULL CHECK (kind IN ('section_welcome','field_help')),
  title text NOT NULL,
  body_md text NOT NULL,
  selector text,
  order_idx int NOT NULL DEFAULT 0,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE UNIQUE INDEX IF NOT EXISTS onboarding_content_section_kind_field_uniq
  ON public.onboarding_content (section, kind, COALESCE(field_key, ''));

GRANT SELECT ON public.onboarding_content TO anon;
GRANT SELECT ON public.onboarding_content TO authenticated;
GRANT ALL ON public.onboarding_content TO service_role;

ALTER TABLE public.onboarding_content ENABLE ROW LEVEL SECURITY;

CREATE POLICY "onboarding_content_read_all"
  ON public.onboarding_content FOR SELECT
  TO anon, authenticated
  USING (true);

CREATE TRIGGER trg_onboarding_content_updated
  BEFORE UPDATE ON public.onboarding_content
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

-- ============================================================
-- employer_tour_state
-- ============================================================
CREATE TABLE IF NOT EXISTS public.employer_tour_state (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL,
  section text NOT NULL CHECK (section IN ('profile','companies','vacancies','interviews','training','crm','billing')),
  status text NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','completed','dismissed')),
  completed_at timestamptz,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now(),
  UNIQUE (user_id, section)
);

GRANT SELECT, INSERT, UPDATE, DELETE ON public.employer_tour_state TO authenticated;
GRANT ALL ON public.employer_tour_state TO service_role;

ALTER TABLE public.employer_tour_state ENABLE ROW LEVEL SECURITY;

CREATE POLICY "tour_state_own_select" ON public.employer_tour_state
  FOR SELECT TO authenticated USING (user_id = auth.uid());
CREATE POLICY "tour_state_own_insert" ON public.employer_tour_state
  FOR INSERT TO authenticated WITH CHECK (user_id = auth.uid());
CREATE POLICY "tour_state_own_update" ON public.employer_tour_state
  FOR UPDATE TO authenticated USING (user_id = auth.uid()) WITH CHECK (user_id = auth.uid());
CREATE POLICY "tour_state_own_delete" ON public.employer_tour_state
  FOR DELETE TO authenticated USING (user_id = auth.uid());

CREATE TRIGGER trg_employer_tour_state_updated
  BEFORE UPDATE ON public.employer_tour_state
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

-- ============================================================
-- SEED
-- ============================================================
INSERT INTO public.onboarding_content (section, field_key, kind, title, body_md, order_idx) VALUES
('profile', NULL, 'section_welcome', 'Профиль работодателя — ваша визитка в RR',
'Добро пожаловать в раздел **Профиль**! Здесь живёт всё, что характеризует вас как работодателя на платформе «Робот Рекрутер» (RR): контактные данные, аватар, публичный идентификатор `empNNN`, баланс RR-кредитов и реферальная ссылка.

**Зачем заполнять?** От полноты профиля зависят три вещи: (1) как вас видят кандидаты в публичных карточках вакансий и лендингах компаний; (2) насколько быстро служба поддержки решит ваш вопрос — у нас есть телефон и email; (3) персональные рекомендации ИИ-ассистента по тарифам и сценариям найма.

**Что обязательно?** Имя/название, контактный email (для уведомлений системы и счёт-фактур), телефон (для срочных ситуаций и Робокассы), часовой пояс (от него зависит расписание автоматических напоминаний кандидатам и cron-задач).

**Баланс RR-кредитов** отображается прямо в шапке профиля: 1 RR ≈ 1 рубль (см. тарифы). При регистрации мы начисляем приветственные **1000 RR** — этого хватает на полноценный тест-драйв одной вакансии. Реферальная ссылка `?ref=empNNN` приносит вам и приглашённому коллеге по 1000 RR за каждую активацию.

**Что дальше?** После заполнения профиля переходите в раздел «Компании» — без хотя бы одной компании нельзя создавать вакансии. Если что-то непонятно — наведите на «?» рядом с полем или нажмите «Запустить тур заново» в правом верхнем углу.', 1),

('companies', NULL, 'section_welcome', 'Компании — фундамент ваших вакансий',
'Раздел **Компании** — это карточки юр. лиц или брендов, от имени которых вы публикуете вакансии. Один работодатель может вести **несколько компаний** (например, агентство ведёт найм сразу для нескольких клиентов) — каждая со своим лендингом, набором документов и стилем.

**Зачем нужна компания?** Каждая вакансия обязательно привязывается к компании, и кандидат видит её карточку перед откликом: чем подробнее заполнено, тем выше конверсия в собеседование. По нашей статистике компании с описанием 500+ символов, тремя фото офиса и блоком «социальный пакет» получают **в 2,3 раза больше откликов**.

**Что внутри карточки?** Название, ИНН/ОГРН (для счетов), регион, индустрия, размер, миссия, описание, фото офиса/команды, документы (welcome-pack, корпоративная книга, кодекс), список соц. бенефитов, ссылки на сайт и соцсети. Всё это собирается в красивый **публичный лендинг** `/company/<slug>` — его можно отправить кандидату в одном клике.

**ИИ-помощь.** Загрузите PDF/DOCX о компании — кнопка «Анализировать документ» извлечёт ключевые факты, и поля заполнятся автоматически. Можно ещё короче: одна кнопка «Оформить красиво» приведёт черновик к фирменному виду RR.

**Что дальше?** Сохраните минимум одну компанию — после этого разблокируется шаг 3 «Вакансии». Если вы хотите параллельно вести несколько брендов, создайте все нужные карточки сразу.', 1),

('vacancies', NULL, 'section_welcome', 'Вакансии — сердце воронки найма',
'Раздел **Вакансии** — место, где рождается каждая воронка. Вакансия в RR — это не просто текст, а целый «проект найма» с настройками автоматического скоринга, тестов, обучения и интервью.

**Что описывается в вакансии?** Должность, требования, обязанности, soft/hard skills, регион/удалёнка, диапазон зарплаты, формат занятости, ключевые KPI первых 30/60/90 дней, чек-лист «красных флагов» для авто-отсева. RR-ассистент превратит ваш сырой текст или PDF-описание в структурированную вакансию за 1–2 минуты.

**Скоринг и проходной балл.** По умолчанию **70 баллов** — кандидат, набравший ≥70, автоматически попадает в CRM и присылает вам in-app уведомление. Можно настроить порог индивидуально под каждую вакансию: для топ-менеджеров 85+, для линейного персонала — 55+.

**Автоматизация.** К вакансии можно прикрепить: тест-задание (генерируется ИИ), обучающий курс (раздел «Обучения»), AI-интервью с грейдингом ответов (раздел «Интервью»). Эти шаги кандидат проходит самостоятельно, а вы получаете итоговый отчёт с баллами и рекомендацией.

**Стоимость.** Создание вакансии бесплатное; списываются RR-кредиты только за реальные действия ИИ (анализ резюме, грейд интервью, генерация обучения). Полный прайс — в разделе «Счета» и в публичной оферте.

**Что дальше?** Создайте первую вакансию через кнопку «Новая вакансия». После сохранения откроется доступ к Обучениям и Интервью.', 1),

('interviews', NULL, 'section_welcome', 'Интервью — ИИ-собеседник 24/7',
'Раздел **Интервью** — конструктор автоматических AI-собеседований. Кандидат проходит интервью в удобное время, RR оценивает ответы по вашим критериям и присылает отчёт.

**Из чего состоит интервью?** Это набор блоков: разделы-чек-листы (например, «коммуникация», «стрессоустойчивость»), кейсы-ситуации с открытым ответом, проверки резюме на соответствие требованиям. Можно собрать вручную или сгенерировать одной кнопкой по тексту вакансии.

**Как RR оценивает?** Каждый ответ кандидата прогоняется через LLM с вашими критериями и эталонными ответами; модель ставит балл от 0 до 100 и пишет краткое обоснование. Все баллы сворачиваются в итоговую оценку и сравниваются с проходным порогом вакансии.

**Что видит кандидат?** Дружелюбный чат-интерфейс с маскотом RR, голосовой/текстовый ввод, прогресс-бар. Никаких «капканов» — все вопросы открытые, формат комфортный.

**Когда привязывать интервью?** Обычно — после прохождения обучения и теста, как финальный фильтр перед живым собеседованием с HR. Но можно ставить интервью и в начало — как замену скрин-звонку.

**Стоимость.** Списание RR происходит за каждый сгенерированный или оценённый ответ (см. калькулятор найма на лендинге). Тариф можно посмотреть прямо в редакторе блока.

**Что дальше?** Создайте первое интервью или скопируйте шаблон из библиотеки. Без интервью можно обойтись, если вы используете только тест-задания и обучение.', 1),

('training', NULL, 'section_welcome', 'Обучения — онбординг до выхода на работу',
'Раздел **Обучения** — это конструктор pre-employment курсов и онбординг-материалов. Кандидат проходит мини-обучение **до** того, как вы потратите время на живое собеседование: вы сразу видите, кто справился, а кто нет.

**Зачем учить кандидата до найма?** Это самый дешёвый способ отфильтровать «не готовых», адаптировать «почти готовых» и сразу вывести на работу «готовых». По данным RR, **34% работодателей** сокращают срок выхода нового сотрудника в продуктивность вдвое именно за счёт pre-employment обучения.

**Что внутри курса?** Уроки (markdown с картинками, видео, файлами), тесты с авто-проверкой ИИ, кейсы, чек-листы, финальная сертификация. Курс делится на этапы (`stages`) — например: «1. О компании», «2. Продукт», «3. Скрипты», «4. Регламенты», «5. Финальный экзамен».

**ИИ-генерация.** Кнопка «Сгенерировать обучение» создаёт полный курс по вашей вакансии за 2–4 минуты: подбирает темы, пишет уроки, формирует тесты. Дальше вы редактируете под себя.

**Прогресс кандидата.** В реальном времени видно: на каком этапе он сейчас, сколько баллов набрал, где «застрял». Если кандидат бросил обучение на 48 часов — система автоматически пришлёт ему напоминание (раздел «Уведомления»).

**Сертификация.** Успешное прохождение генерирует сертификат и отправляет вам in-app уведомление «Кандидат прошёл обучение».

**Что дальше?** Сначала создайте вакансию, потом — обучение к ней. Без вакансии раздел заблокирован.', 1),

('crm', NULL, 'section_welcome', 'CRM — все кандидаты в одном месте',
'Раздел **CRM** — единый центр управления воронкой кандидатов по всем вакансиям. Две раскладки: **канбан** (по стадиям воронки) и **таблица** (для аналитики и массовых действий).

**Стадии воронки.** По умолчанию RR создаёт колонки: «Новый», «Резюме», «Обучение», «Интервью», «Готов к найму», «Приглашён», «Отказ». Состав можно настроить под ваш процесс.

**Карточка кандидата.** Содержит: контакты, резюме (с парсингом ИИ), все ответы и баллы по интервью/обучению, историю переходов между стадиями, заметки рекрутера, AI-сводку «сильные/слабые стороны», итоговый балл и рекомендацию.

**Решение по кандидату.** В карточке две кнопки: «Пригласить» и «Отказать». При нажатии вы пишете сообщение, кандидат получает in-app уведомление и баннер с решением в своём кабинете. История решений хранится в полях `hire_decision` и `hire_message`.

**Автоматизация.** При достижении проходного балла (по умолчанию 70) кандидат сам поднимается выше по воронке, и вам приходит уведомление «Подходящий кандидат». При получении сертификата — отдельное уведомление.

**Фильтры и поиск.** По вакансии, стадии, баллу, дате, источнику. В таблице можно экспортировать выгрузку в CSV.

**Что дальше?** CRM наполняется автоматически по мере того, как кандидаты откликаются и проходят шаги. На старте здесь будет пусто — сначала опубликуйте вакансию и поделитесь ссылкой.', 1),

('billing', NULL, 'section_welcome', 'Счета и баланс — оплата без сюрпризов',
'Раздел **Счета** — финансовый центр кабинета. Здесь живёт баланс RR-кредитов, история всех операций (списания за ИИ, начисления бонусов, пополнения через Робокассу), счета-фактуры и реквизиты для бухгалтерии.

**Как устроено списание?** Все ИИ-операции тарифицируются в RR: анализ резюме, генерация вакансии/обучения/интервью, оценка ответов кандидатов, рассылки. Перед каждой дорогой операцией система показывает диалог «Подтвердите списание X RR». Полный прайс — на лендинге и в публичной оферте.

**Пополнение.** Через интеграцию с **Робокассой** — карта, СБП, ЮMoney, расчётный счёт юр. лица. Минимальная сумма — 500 ₽, без скрытых комиссий. После оплаты RR зачисляются мгновенно (в 99% случаев — за 5 секунд).

**Бонусы и приветственный пакет.** При регистрации — +1000 RR. По реферальной ссылке — ещё +1000 вам и +1000 другу за каждую успешную регистрацию (см. «Профиль»).

**Тарифы.** Все цены ИИ-операций можно посмотреть в калькуляторе найма на лендинге (`/`) или спросить у ИИ-ассистента в кабинете («Расскажи цены»). Подписочной модели нет — платите только за то, что реально используете.

**Документы.** Чеки и счёт-фактуры (с НДС, если применимо) генерируются автоматически после каждой оплаты. Скачать — кнопка «Документы» рядом с операцией.

**Что дальше?** Если баланса хватает, ничего делать не надо. Перед первой генерацией обучения/интервью рекомендуем держать запас 1500–3000 RR.', 1);

INSERT INTO public.onboarding_content (section, field_key, kind, title, body_md, order_idx) VALUES
('profile','full_name','field_help','ФИО / Контактное лицо','Имя, которое увидят кандидаты в подписи писем и менеджер поддержки RR при обращении. Можно указывать в формате «Имя Фамилия» или «Имя, должность». Не используется в публичных лендингах — только во внутренних коммуникациях.',1),
('profile','email','field_help','Email','Адрес для всех системных уведомлений: новые отклики, прохождение порога, бухгалтерские документы. По нему же восстанавливается пароль. Рекомендуем корпоративный ящик — личные часто блокируют письма от Робокассы.',2),
('profile','phone','field_help','Телефон','Используется службой поддержки при срочных ситуациях (списание, оплата, блокировка), а также Робокассой для подтверждения платежей. Формат — международный, начиная с +7. Никому из кандидатов не показывается.',3),
('profile','timezone','field_help','Часовой пояс','От него зависит расписание автоматических напоминаний кандидатам («бросил интервью 24 ч», «бросил обучение 48 ч») и время отправки in-app уведомлений. По умолчанию определяется браузером.',4),
('profile','avatar','field_help','Аватар','Картинка-логотип, видна в шапке кабинета и в письмах кандидатам. Рекомендуем PNG ≥ 200×200 с прозрачным фоном или фирменный логотип компании. Хранится в Supabase Storage, обновляется мгновенно.',5),
('profile','public_id','field_help','Публичный ID (empNNN)','Уникальный идентификатор вашего кабинета (`emp123`). Используется в реферальных ссылках (`?ref=emp123`) и публичных URL-ах. Изменить нельзя — закреплён за аккаунтом навсегда.',6),
('profile','balance','field_help','Баланс RR','Текущий баланс RR-кредитов (1 RR ≈ 1 ₽). Из него списываются все ИИ-операции. Пополнить можно во вкладке «Счета». При балансе < 100 RR появится предупреждение в шапке.',7),
('profile','referral_link','field_help','Реферальная ссылка','Ссылка вида `https://hr-rr.ru/?ref=empNNN`. Каждый зарегистрировавшийся по ней работодатель приносит вам +1000 RR на баланс (и сам получает 1000 RR в подарок). Бонус начисляется один раз за уникального пользователя.',8),

('companies','name','field_help','Название компании','Бренд или юр. наименование, как видят кандидаты. Можно указывать оба варианта: «Acme («Акме Технологии», ООО)». Это поле формирует заголовок публичного лендинга и URL-slug.',1),
('companies','inn','field_help','ИНН','Идентификационный номер налогоплательщика. Нужен для счетов и закрывающих документов. 10 цифр для юр. лиц, 12 — для ИП. Поле скрыто от кандидатов.',2),
('companies','region','field_help','Регион / Город','Где находится главный офис. Используется в карточках вакансий и фильтрах поиска. Можно указать «Удалённая компания», если у вас нет физического офиса.',3),
('companies','industry','field_help','Индустрия','Отрасль: IT, e-commerce, ритейл, производство и т.д. Помогает кандидатам сориентироваться и подключает релевантные шаблоны вакансий/обучения от ИИ.',4),
('companies','size','field_help','Размер компании','Численность сотрудников: 1–10, 11–50, 51–200, 201–1000, 1000+. Влияет на восприятие компании кандидатом и на рекомендации RR по тарифам.',5),
('companies','description','field_help','Описание компании','Главный текст для лендинга компании. Минимум 500 символов: миссия, чем занимаетесь, для кого, ключевые цифры. Чем подробнее — тем выше конверсия в отклик.',6),
('companies','benefits','field_help','Социальный пакет','Список бенефитов: ДМС, спорт, обучение, релокация, опционы. Лучше списком с эмодзи. Кандидаты с релевантным опытом обращают на этот блок внимание в первую очередь.',7),
('companies','logo','field_help','Логотип','Фирменный знак, показывается на лендинге и в карточках вакансий. PNG/SVG с прозрачным фоном, ≥ 400×400. Хранится в Supabase Storage.',8),
('companies','documents','field_help','Документы компании','Welcome-pack, корпоративная книга, кодекс, кейсы. Загруженные PDF/DOCX автоматически парсятся ИИ — их содержимое попадает в базу знаний и помогает кандидатам в обучении.',9),
('companies','public_slug','field_help','Публичный URL','Адрес лендинга компании вида `/company/<slug>`. Slug формируется из названия, но его можно отредактировать. Используйте короткие латинские буквы и дефисы.',10),
('companies','ai_analyze','field_help','Анализировать документ','Загрузите PDF/DOCX о компании, и ИИ извлечёт ключевые поля автоматически: миссию, размер, продукты, регион, бенефиты. Списывает RR за токены — обычно 5–15 RR за документ.',11),
('companies','ai_polish','field_help','Оформить красиво','Кнопка прогоняет черновик описания через ИИ и приводит к структуре RR: миссия → продукт → команда → культура → бенефиты → CTA. Стоимость — 8–20 RR.',12),

('vacancies','title','field_help','Название вакансии','Точное наименование позиции: «Senior Backend Developer (Python/FastAPI)». Это поле — основной заголовок в публичной карточке и в поиске. Избегайте кликбейта типа «Гуру кода».',1),
('vacancies','company','field_help','Компания','К какой компании из вашего списка относится вакансия. Без компании создать вакансию нельзя — сначала заполните раздел «Компании».',2),
('vacancies','description','field_help','Описание / Требования','Полный текст вакансии: про задачи, требования, условия. Можно сгенерировать ИИ из короткой выжимки или загрузить готовый файл — кнопка «Извлечь из документа».',3),
('vacancies','salary','field_help','Зарплата','Вилка «от — до» в рублях/у.е., gross или net. Вакансии с открытой вилкой получают на 40% больше откликов. Можно скрыть от кандидатов галочкой «не показывать».',4),
('vacancies','format','field_help','Формат','Офис / гибрид / удалёнка / разъездной. От этого зависит, какие фильтры подключатся в каталоге `/vacancies`.',5),
('vacancies','score_threshold','field_help','Проходной балл','Минимальный балл (0–100), при котором кандидат считается подходящим. По умолчанию 70. При достижении порога вам приходит in-app уведомление и кандидат отмечается зелёным в CRM.',6),
('vacancies','resume_criteria','field_help','Критерии резюме','Список тем/навыков/опыта, по которым ИИ оценивает резюме кандидата. Пример: «Python ≥ 3 года», «опыт с PostgreSQL», «английский B2+». Можно сгенерировать кнопкой.',7),
('vacancies','checklist','field_help','Чек-лист собеседования','Soft/hard skills для проверки на интервью. Каждый пункт — отдельная тема, по которой задаются 1–3 вопроса. Используется при сборке AI-интервью.',8),
('vacancies','situations','field_help','Кейсы-ситуации','Открытые кейсы с примерным эталонным ответом. RR оценивает ответ кандидата по семантической близости к эталону и логике. 3–5 кейсов на вакансию — оптимум.',9),
('vacancies','onboarding_link','field_help','Привязать обучение','Какой курс из раздела «Обучения» проходит кандидат после успешного скрина. Можно оставить пустым, если обучение не требуется.',10),
('vacancies','status','field_help','Статус вакансии','Черновик / Активна / Пауза / Закрыта. Только активные вакансии видны в публичном каталоге и принимают отклики.',11),

('interviews','name','field_help','Название интервью','Внутреннее имя сценария: «Senior backend — финальный фильтр», «Sales — стрессовое». Видно только вам и команде, кандидату не показывается.',1),
('interviews','linked_vacancy','field_help','Вакансия','С какой вакансией связан этот сценарий. Один сценарий можно использовать в нескольких вакансиях — выберите основную для удобства аналитики.',2),
('interviews','blocks','field_help','Блоки интервью','Из чего состоит сценарий: проверка резюме, чек-лист тем, кейсы-ситуации. Каждый блок добавляется отдельной кнопкой и редактируется независимо.',3),
('interviews','duration_target','field_help','Целевая длительность','Сколько по плану длится интервью для кандидата: 10/20/40 минут. На основании этого RR подбирает количество вопросов и глубину.',4),
('interviews','grading_strictness','field_help','Строгость оценки','Мягкая / средняя / жёсткая. Влияет на пороги в LLM-промптах: жёсткая ставит низкий балл за неполные ответы, мягкая — наоборот.',5),
('interviews','generate_button','field_help','Сгенерировать из вакансии','Кнопка автоматически собирает интервью по тексту вакансии: достаёт критерии из «Резюме», темы из «Чек-листа», кейсы из «Ситуаций». Стоимость — 20–60 RR.',6),
('interviews','preview','field_help','Превью кандидата','Открывает интервью в режиме «глазами кандидата». Полезно прогнать перед публикацией, чтобы поймать неудобные формулировки.',7),
('interviews','results_view','field_help','Просмотр результатов','По каждому пройденному интервью RR показывает: ответы кандидата, баллы по блокам, обоснование LLM, итоговую оценку, рекомендацию.',8),

('training','name','field_help','Название курса','Заголовок курса для кандидата: «Онбординг продакт-менеджера», «Введение в скрипты продаж». Видно в кабинете кандидата на первой странице обучения.',1),
('training','linked_vacancy','field_help','Вакансия','С какой вакансией связано обучение. Если кандидат пришёл по этой вакансии, курс предлагается автоматически после прохождения скрина.',2),
('training','stages','field_help','Этапы (stages)','Курс делится на этапы — обычно 3–7. Кандидат проходит их последовательно: каждый этап = уроки + финальный тест. Можно блокировать переход дальше, пока не сдан тест.',3),
('training','lesson','field_help','Урок','Один экран контента: markdown-текст, картинки, видео, файлы, ссылки. Длительность — 3–15 минут чтения. Слишком длинные уроки лучше дробить.',4),
('training','stage_test','field_help','Тест этапа','Финальная проверка знаний по этапу: 5–15 вопросов разных типов (выбор, мульти-выбор, открытый ответ с авто-проверкой ИИ). Проходной балл задаётся отдельно.',5),
('training','generate_button','field_help','Сгенерировать обучение','ИИ создаёт полный курс из текста вакансии и документов компании за 2–4 минуты: подбирает темы, пишет уроки, формирует тесты. Стоимость — 80–250 RR за курс.',6),
('training','generate_quiz','field_help','Сгенерировать тест','По выбранному этапу/уроку ИИ собирает тест с разнообразными вопросами. Можно редактировать вручную, добавлять варианты, менять формулировки.',7),
('training','certification','field_help','Сертификация','Финальный «экзамен» курса. После успешного прохождения система генерирует сертификат и присылает вам in-app уведомление «Кандидат прошёл обучение».',8),
('training','progress','field_help','Прогресс кандидата','Видно по каждому кандидату: текущий этап, % выполнения, баллы за тесты, дата последней активности. Если бросил на 48 ч — система пришлёт напоминание.',9),

('crm','view_toggle','field_help','Канбан / Таблица','Переключатель раскладки. Канбан — для визуального ведения воронки, таблица — для аналитики и массовых действий (экспорт, изменение стадии у группы).',1),
('crm','stages','field_help','Колонки воронки','Стадии: Новый → Резюме → Обучение → Интервью → Готов к найму → Приглашён / Отказ. Состав колонок можно настроить под ваш процесс.',2),
('crm','candidate_card','field_help','Карточка кандидата','Открывает полное досье: контакты, резюме, баллы по этапам, история стадий, заметки, AI-сводка, итоговая оценка и рекомендация.',3),
('crm','score','field_help','Балл кандидата','Итоговая оценка 0–100, посчитанная по интервью/обучению. Зелёный = выше проходного, жёлтый = около, красный = ниже. Сортировка по убыванию по умолчанию.',4),
('crm','filters','field_help','Фильтры','По вакансии, стадии, баллу, дате отклика, источнику (UTM, реферал, прямой). Используйте для еженедельного план-факта по найму.',5),
('crm','hire_decision','field_help','Пригласить / Отказать','Кнопки в карточке кандидата. При нажатии вы пишете сообщение, кандидат получает in-app уведомление и видит баннер с решением в своём кабинете.',6),
('crm','notes','field_help','Заметки рекрутера','Внутренние комментарии, видны только вашей команде. Удобно фиксировать впечатления от живого собеседования, договорённости по зарплате и т.п.',7),
('crm','export_csv','field_help','Экспорт CSV','Выгрузка таблицы кандидатов в CSV для внешней аналитики или HR-системы. Включает все поля, включая баллы и стадии.',8),
('crm','search','field_help','Поиск','По имени, email, телефону, тегам в резюме. Быстрый способ найти конкретного кандидата без фильтров.',9),

('billing','balance','field_help','Текущий баланс RR','Сколько RR-кредитов сейчас доступно для ИИ-операций. 1 RR ≈ 1 ₽. Перед дорогой операцией система показывает диалог подтверждения списания.',1),
('billing','topup','field_help','Пополнить через Робокассу','Кнопка открывает форму оплаты: карта, СБП, ЮMoney, расчётный счёт. Минимум 500 ₽. RR зачисляются мгновенно после успешной оплаты.',2),
('billing','operations','field_help','История операций','Все движения по балансу: списания за ИИ, начисления бонусов, пополнения. С фильтром по дате и типу. Используется для сверки с бухгалтерией.',3),
('billing','invoices','field_help','Счета и чеки','Закрывающие документы: чек ОФД, счёт-фактура (с НДС, если применимо). Генерируются автоматически после каждой оплаты. Скачиваются в PDF.',4),
('billing','requisites','field_help','Реквизиты для счёта','ИНН/КПП, юр. адрес, расчётный счёт — нужны для безналичной оплаты от юр. лица. Сохраняются один раз и подставляются в счёт автоматически.',5),
('billing','spend_confirm','field_help','Подтверждение списания','Диалог, который появляется перед дорогими ИИ-операциями (генерация курса, массовый грейд). Можно отключить для операций < 50 RR в настройках профиля.',6),
('billing','tariff_info','field_help','Тарифы операций','Все цены ИИ-действий: анализ резюме, грейд интервью, генерация обучения. Подробный калькулятор — на лендинге, краткая справка — у ИИ-ассистента в правом нижнем углу.',7),
('billing','bonuses','field_help','Бонусы и подарки','Приветственные +1000 RR при регистрации, +1000 RR за каждого приглашённого друга. Все начисления видны в истории операций с пометкой «Бонус».',8);
